previewCss:
.darma-loader-darma-custom-757 {
  color: var(--loader-color, #ec4899);
  --loader-secondary-color: #f9a8d4;
  --loader-bg: #ffffff;
height: 15px;
aspect-ratio: 5;
display: grid;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
}
.darma-loader-darma-custom-757:before,
.darma-loader-darma-custom-757:after {
content: "";
grid-area: 1/1;
background:
var(--_g) left,
var(--_g) right;
background-size: 20% 100%;
animation: darma-loader-darma-custom-757-l32 1s infinite;
}
.darma-loader-darma-custom-757:after {
background:
var(--_g) calc(1*100%/3),
var(--_g) calc(2*100%/3);
background-size: 20% 100%;
animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-757-l32 {
80%,100% {transform:rotate(.5turn)}
}

